import React, { useEffect, useState } from "react";
import axios from "axios";
import { useAuth } from "../context/AuthContext";
import InternshipCard from "../components/InternshipCard";
import { useNavigate } from "react-router-dom";

export default function Internship() {
  const { currentUser } = useAuth();
  const navigate = useNavigate();

  const [internships, setInternships] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [filterLocation, setFilterLocation] = useState("");
  const [filterCompany, setFilterCompany] = useState("");

  useEffect(() => {
    const fetchInternships = async () => {
      try {
        const res = await axios.get("http://localhost:5000/api/internships");
        setInternships(res.data);
      } catch (err) {
        console.error("Failed to fetch internships:", err);
      }
    };
    fetchInternships();
  }, []);

  const filteredInternships = internships.filter((internship) => {
    const matchesTitle = internship.title
      .toLowerCase()
      .includes(searchTerm.toLowerCase());
    const matchesLocation = internship.location
      .toLowerCase()
      .includes(filterLocation.toLowerCase());
    const matchesCompany = internship.company
      .toLowerCase()
      .includes(filterCompany.toLowerCase());

    return matchesTitle && matchesLocation && matchesCompany;
  });

  return (
    <div className="p-6 max-w-6xl mx-auto">
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-3xl font-bold text-gray-800">Available Internships</h1>
        {(currentUser?.role === "admin" || currentUser?.role === "hr") && (
          <button
            onClick={() => navigate("/post-internship")}
            className="bg-green-600 hover:bg-green-700 text-white px-5 py-2 rounded-md font-medium transition duration-200"
          >
            + Post Internship
          </button>
        )}
      </div>

      {/* Filters */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-6">
        <input
          type="text"
          placeholder="Search by Title"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="border px-3 py-2 rounded shadow-sm"
        />
        <input
          type="text"
          placeholder="Filter by Location"
          value={filterLocation}
          onChange={(e) => setFilterLocation(e.target.value)}
          className="border px-3 py-2 rounded shadow-sm"
        />
        <input
          type="text"
          placeholder="Filter by Company"
          value={filterCompany}
          onChange={(e) => setFilterCompany(e.target.value)}
          className="border px-3 py-2 rounded shadow-sm"
        />
      </div>

      {/* Internship Cards */}
      <div className="grid md:grid-cols-2 gap-6">
        {filteredInternships.length > 0 ? (
          filteredInternships.map((internship) => (
            <InternshipCard
              key={internship._id}
              internship={internship}
              fetchInternships={() => {}}
            />
          ))
        ) : (
          <p className="text-gray-600">No internships found.</p>
        )}
      </div>
    </div>
  );
}
